!function(){
  const AUDIT_KEY="CBT_ADMIN_AUDIT_LOG_V1";
  const esc=v=>v==null?"":String(v).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]));
  const q=id=>document.getElementById(id);
  const fmtTime=v=>{if(!v)return"-";const d=new Date(Number(v));return isNaN(d.getTime())?"-":d.toLocaleString("id-ID",{dateStyle:"medium",timeStyle:"short"})};
  const statusOf=j=>{const now=Date.now();if(j.aktif===false||String(j.status||"").toUpperCase()==="NONAKTIF")return{key:"nonaktif",label:"NONAKTIF",color:"#64748b",bg:"#f1f5f9"};if(j.force_aktif)return{key:"override",label:"OVERRIDE",color:"#b91c1c",bg:"#fee2e2"};if(Number(j.selesai)&&now>Number(j.selesai))return{key:"tutup",label:"TUTUP",color:"#dc2626",bg:"#fee2e2"};if(Number(j.mulai)&&now<Number(j.mulai))return{key:"belum",label:"BELUM MULAI",color:"#c2410c",bg:"#ffedd5"};return{key:"aktif",label:"AKTIF",color:"#059669",bg:"#dcfce7"}};
  const readAudit=()=>{try{return JSON.parse(localStorage.getItem(AUDIT_KEY)||"[]")}catch(e){return[]}};
  const writeAudit=list=>localStorage.setItem(AUDIT_KEY,JSON.stringify(list.slice(0,100)));
  async function audit(action,detail){
    const entry={time:Date.now(),action,detail};
    const list=[entry,...readAudit()];writeAudit(list);
    renderAuditLog();
    try{window.db&&db.ref&&await db.ref("/audit_log/"+entry.time).set(entry)}catch(e){}
  }
  function readiness(j,bank){
    const count=bank&&j.nama_soal&&bank[j.nama_soal]?Object.keys(bank[j.nama_soal]).length:0;
    const checks=[
      {ok:!!j.nama_soal&&count>0,label:count>0?count+" soal":"Soal kosong"},
      {ok:!!String(j.token||"").trim(),label:j.token?"Token ada":"Token kosong"},
      {ok:Number(j.mulai)>0&&Number(j.selesai)>Number(j.mulai),label:"Waktu valid"},
      {ok:!!String(j.target_kelas||j.kelas||"").trim(),label:j.target_kelas||j.kelas||"Semua kelas"},
      {ok:j.aktif!==false,label:j.aktif!==false?"Tampil siswa":"Nonaktif"}
    ];
    return checks;
  }
  function renderChecklist(checks){
    return `<div class="admin-ready-list">${checks.map(c=>`<span class="admin-ready-chip ${c.ok?"ok":"bad"}">${c.ok?"✓":"!"} ${esc(c.label)}</span>`).join("")}</div>`;
  }
  function injectJadwalToolbar(){
    if(q("admin-jadwal-toolbar"))return;
    const tab=q("tab-jadwal"), first=tab&&tab.querySelector(".admin-card");
    if(!first)return;
    first.innerHTML=`<div id="admin-jadwal-toolbar" class="admin-ops-toolbar">
      <button class="btn btn-primary" onclick="openJadwalModal()">+ Tambah Jadwal</button>
      <input id="admin-jadwal-search" class="form-control" placeholder="Cari jadwal/bank/kelas..." oninput="loadAdminJadwal()">
      <select id="admin-jadwal-status-filter" class="form-control" onchange="loadAdminJadwal()">
        <option value="all">Semua Status</option><option value="aktif">Aktif</option><option value="nonaktif">Nonaktif</option><option value="belum">Belum Mulai</option><option value="tutup">Tutup</option>
      </select>
      <button class="btn btn-outline" onclick="bulkSetJadwalActive(true)">Aktifkan</button>
      <button class="btn btn-outline" onclick="bulkSetJadwalActive(false)">Nonaktifkan</button>
      <button class="btn btn-outline" onclick="bulkRegenerateTokens()">Token Baru</button>
    </div>`;
  }
  function injectAuditCard(){
    if(q("admin-audit-card"))return;
    const settings=q("tab-settings");
    if(!settings)return;
    const card=document.createElement("div");
    card.className="admin-card";
    card.id="admin-audit-card";
    card.style.marginTop="16px";
    card.innerHTML='<h3 style="margin:0 0 12px;font-size:1rem;">Audit Aktivitas Admin</h3><div id="admin-audit-log" class="admin-audit-log"></div>';
    settings.appendChild(card);
    renderAuditLog();
  }
  function renderAuditLog(){
    const el=q("admin-audit-log");if(!el)return;
    const list=readAudit().slice(0,20);
    el.innerHTML=list.length?list.map(x=>`<div class="admin-audit-row"><span>${fmtTime(x.time)}</span><strong>${esc(x.action)}</strong><small>${esc(x.detail||"")}</small></div>`).join(""):'<div class="text-muted" style="font-size:.85rem;">Belum ada aktivitas terekam.</div>';
  }
  async function getJadwalData(){
    window.dbConnectFast&&await window.dbConnectFast();
    const [j,b]=await Promise.all([db.ref("/jadwal").once("value"),db.ref("/soal").once("value")]);
    return{jadwal:j.val()||{},bank:b.val()||{}};
  }
  window.loadAdminJadwal=async function(){
    const tbody=q("admin-jadwal-tbody");if(!tbody)return;
    injectJadwalToolbar();
    showLoading&&showLoading("Memuat Jadwal...");
    try{
      const {jadwal,bank}=await getJadwalData();
      const search=(q("admin-jadwal-search")?.value||"").toLowerCase();
      const filter=q("admin-jadwal-status-filter")?.value||"all";
      let rows=Object.entries(jadwal).filter(([id,j])=>{
        const st=statusOf(j).key;
        const hay=(id+" "+(j.nama||"")+" "+(j.nama_soal||"")+" "+(j.target_kelas||j.kelas||"")).toLowerCase();
        return (!search||hay.includes(search))&&(filter==="all"||st===filter);
      });
      rows.sort((a,b)=>(Number(a[1].mulai)||0)-(Number(b[1].mulai)||0));
      tbody.innerHTML=rows.length?rows.map(([id,j])=>{
        const st=statusOf(j), checks=readiness(j,bank), ready=checks.filter(c=>c.ok).length;
        return `<tr>
          <td>
            <label class="admin-row-check"><input type="checkbox" class="admin-jadwal-check" value="${esc(id)}"><span></span></label>
            <div style="font-weight:800;">${esc(j.nama||id)}</div>
            <div style="font-size:.72rem;color:var(--text-muted);">${esc(id)} · Bank: ${esc(j.nama_soal||"-")} · ${esc(j.target_kelas||j.kelas||"Semua kelas")}</div>
            ${renderChecklist(checks)}
          </td>
          <td><div style="font-size:.78rem;"><strong>Mulai</strong><br>${fmtTime(j.mulai)}</div><div style="font-size:.78rem;margin-top:6px;"><strong>Selesai</strong><br>${fmtTime(j.selesai)}</div></td>
          <td><div class="admin-status-pill" style="background:${st.bg};color:${st.color};">${st.label}</div><code class="admin-token-code">${esc(j.token||"-")}</code><div style="font-size:.7rem;color:${ready===checks.length?"#059669":"#c2410c"};margin-top:6px;">Siap: ${ready}/${checks.length}</div></td>
          <td><div class="admin-action-wrap">
            <button class="btn btn-outline" onclick="openJadwalModal('${esc(id)}')">Edit</button>
            <button class="btn btn-outline" onclick="toggleJadwalActive('${esc(id)}', ${j.aktif===false?"true":"false"})">${j.aktif===false?"Aktifkan":"Nonaktifkan"}</button>
            <button class="btn btn-outline" onclick="regenerateJadwalToken('${esc(id)}')">Token</button>
            <button class="btn btn-outline" onclick="openAnalisisModal('${esc(id)}', this.dataset.nama)" data-nama="${esc(j.nama||id)}">Analisis</button>
            <button class="btn btn-outline" onclick="openPrintModal('${esc(id)}', this.dataset.nama)" data-nama="${esc(j.nama||id)}">Cetak</button>
            <button class="btn btn-outline danger" onclick="deleteJadwal('${esc(id)}')">Hapus</button>
          </div></td>
        </tr>`;
      }).join(""):'<tr><td colspan="4" class="text-center text-muted">Tidak ada jadwal sesuai filter.</td></tr>';
    }catch(e){console.error(e);showCustomAlert&&showCustomAlert("Gagal","Gagal memuat jadwal: "+e.message,"❌")}
    finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  const originalOpen=window.openJadwalModal;
  window.openJadwalModal=async function(id=null){
    await originalOpen(id);
    const aktif=q("jAktif");
    if(aktif){aktif.checked=id?aktif.checked:false;const label=document.querySelector('label[for="jAktif"]');if(label)label.textContent="Aktif (tampil di siswa)";}
    if(!q("jadwal-helper-note")){
      const box=document.createElement("div");
      box.id="jadwal-helper-note";
      box.style.cssText="font-size:.78rem;color:#64748b;background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;padding:10px;";
      box.textContent="Saran: biarkan jadwal Nonaktif sampai bank soal, token, target kelas, dan waktu sudah siap. Jadwal Nonaktif tidak tampil di siswa.";
      const modal=q("jadwal-modal")?.querySelector("div[style*='max-height']");
      modal&&modal.insertBefore(box,modal.firstChild);
    }
  };
  window.saveJadwal=async function(){
    const id=q("jId")?.value.trim(), nama=q("jNama")?.value.trim(), soal=q("jSoal")?.value, mulai=q("jMulai")?.value, selesai=q("jSelesai")?.value;
    const token=(q("jToken")?.value||"").trim().toUpperCase(), dur=Number(q("jDurasi")?.value||0), min=Number(q("jMinSelesai")?.value||0);
    if(!(id&&nama&&soal&&mulai&&selesai&&token))return showCustomAlert("Data Tidak Lengkap","ID, nama, bank soal, token, mulai, dan selesai wajib diisi.","📝");
    const m=new Date(mulai).getTime(), s=new Date(selesai).getTime();
    if(isNaN(m)||isNaN(s)||m>=s)return showCustomAlert("Waktu Tidak Valid","Waktu mulai harus sebelum waktu selesai.","⏰");
    if(dur<=0||min<0||min>dur)return showCustomAlert("Durasi Tidak Valid","Durasi harus lebih dari 0 dan minimum selesai tidak boleh melebihi durasi.","⏱️");
    showLoading&&showLoading("Menyimpan Jadwal...");
    try{
      window.dbConnectFast&&await window.dbConnectFast();
      const old=(await db.ref("/jadwal/"+id).once("value")).val()||{};
      const data={nama,nama_soal:soal,durasi:dur,min_selesai:min,mulai:m,selesai:s,target_kelas:q("jKelas")?.value.trim()||"",kelas:q("jKelas")?.value.trim()||"",shuffle_soal:!!q("jShuffleSoal")?.checked,shuffle_opsi:!!q("jShuffleOpsi")?.checked,aktif:!!q("jAktif")?.checked,token,force_aktif:old.force_aktif||false,status:!!q("jAktif")?.checked?"AKTIF":"NONAKTIF",updated_at:Date.now()};
      await db.ref("/jadwal/"+id).set(data);
      await audit("Simpan Jadwal",`${id} · ${data.aktif?"Aktif":"Nonaktif"}`);
      closeJadwalModal();showCustomAlert&&showCustomAlert("Berhasil","Jadwal berhasil disimpan.","✅");loadAdminJadwal();
    }catch(e){showCustomAlert&&showCustomAlert("Gagal","Gagal menyimpan: "+e.message,"❌")}
    finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  window.toggleJadwalActive=async function(id,next){
    if(!confirm((next?"Aktifkan":"Nonaktifkan")+` jadwal "${id}"? ${next?"Jadwal akan tampil di siswa sesuai kelas/waktu.":"Jadwal akan hilang dari halaman siswa."}`))return;
    showLoading&&showLoading("Mengubah status...");
    try{window.dbConnectFast&&await window.dbConnectFast();await db.ref("/jadwal/"+id).update({aktif:!!next,status:next?"AKTIF":"NONAKTIF",updated_at:Date.now()});await audit("Ubah Status Jadwal",`${id} -> ${next?"Aktif":"Nonaktif"}`);loadAdminJadwal()}catch(e){showCustomAlert&&showCustomAlert("Gagal",e.message,"❌")}finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  window.regenerateJadwalToken=async function(id){
    if(!confirm(`Buat token baru untuk "${id}"? Token lama tidak dipakai lagi.`))return;
    const token=Math.random().toString(36).substring(2,8).toUpperCase();
    showLoading&&showLoading("Membuat token...");
    try{window.dbConnectFast&&await window.dbConnectFast();await db.ref("/jadwal/"+id).update({token,updated_at:Date.now()});await audit("Regenerate Token",`${id} -> ${token}`);loadAdminJadwal();showCustomAlert&&showCustomAlert("Token Baru",`Token ${id}: ${token}`,"🔐")}catch(e){showCustomAlert&&showCustomAlert("Gagal",e.message,"❌")}finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  function selectedIds(){return Array.from(document.querySelectorAll(".admin-jadwal-check:checked")).map(x=>x.value)}
  window.bulkSetJadwalActive=async function(active){
    const ids=selectedIds();if(!ids.length)return showCustomAlert("Pilih Jadwal","Centang jadwal dulu.","ℹ️");
    if(!confirm(`${active?"Aktifkan":"Nonaktifkan"} ${ids.length} jadwal terpilih?`))return;
    showLoading&&showLoading("Memproses bulk...");
    try{window.dbConnectFast&&await window.dbConnectFast();await Promise.all(ids.map(id=>db.ref("/jadwal/"+id).update({aktif:!!active,status:active?"AKTIF":"NONAKTIF",updated_at:Date.now()})));await audit("Bulk Status Jadwal",`${ids.length} jadwal -> ${active?"Aktif":"Nonaktif"}`);loadAdminJadwal()}catch(e){showCustomAlert&&showCustomAlert("Gagal",e.message,"❌")}finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  window.bulkRegenerateTokens=async function(){
    const ids=selectedIds();if(!ids.length)return showCustomAlert("Pilih Jadwal","Centang jadwal dulu.","ℹ️");
    if(!confirm(`Buat token baru untuk ${ids.length} jadwal?`))return;
    showLoading&&showLoading("Membuat token...");
    try{window.dbConnectFast&&await window.dbConnectFast();await Promise.all(ids.map(id=>db.ref("/jadwal/"+id).update({token:Math.random().toString(36).substring(2,8).toUpperCase(),updated_at:Date.now()})));await audit("Bulk Token Baru",`${ids.length} jadwal`);loadAdminJadwal()}catch(e){showCustomAlert&&showCustomAlert("Gagal",e.message,"❌")}finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  window.deleteJadwal=async function(id){
    if(!confirm(`Hapus jadwal "${id}"? Data hasil tidak ikut terhapus.`))return;
    showLoading&&showLoading("Menghapus Jadwal...");
    try{window.dbConnectFast&&await window.dbConnectFast();await db.ref("/jadwal/"+id).remove();await audit("Hapus Jadwal",id);showCustomAlert&&showCustomAlert("Berhasil","Jadwal berhasil dihapus.","✅");loadAdminJadwal()}catch(e){showCustomAlert&&showCustomAlert("Gagal","Gagal menghapus: "+e.message,"❌")}finally{window.dbDisconnect&&window.dbDisconnect();hideLoading&&hideLoading()}
  };
  function injectHasilFilters(){
    if(q("admin-hasil-exam-filter"))return;
    const search=q("admin-hasil-search");if(!search)return;
    const exam=document.createElement("select");exam.id="admin-hasil-exam-filter";exam.className="form-control";exam.style.width="190px";exam.onchange=()=>renderAdminHasilPage(1);
    const cls=document.createElement("select");cls.id="admin-hasil-kelas-filter";cls.className="form-control";cls.style.width="150px";cls.onchange=()=>renderAdminHasilPage(1);
    search.parentElement.insertBefore(exam,search.nextSibling);search.parentElement.insertBefore(cls,exam.nextSibling);
  }
  const oldRenderHasil=window.renderAdminHasilPage;
  window.renderAdminHasilPage=function(page){
    injectHasilFilters();
    const hasil=window.adminState&&window.adminState.hasil||[];
    const exams=[...new Set(hasil.map(x=>x.examId||x.ujian).filter(Boolean))].sort(), classes=[...new Set(hasil.map(x=>x.kelas).filter(Boolean))].sort();
    const examSel=q("admin-hasil-exam-filter"), kelasSel=q("admin-hasil-kelas-filter"), oldExam=examSel?.value||"all", oldKelas=kelasSel?.value||"all";
    if(examSel){examSel.innerHTML='<option value="all">Semua Ujian</option>'+exams.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join("");examSel.value=exams.includes(oldExam)?oldExam:"all"}
    if(kelasSel){kelasSel.innerHTML='<option value="all">Semua Kelas</option>'+classes.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join("");kelasSel.value=classes.includes(oldKelas)?oldKelas:"all"}
    if(oldRenderHasil){
      const original=window.adminState.hasil;
      window.adminState.hasil=original.filter(x=>(!examSel||examSel.value==="all"||String(x.examId||x.ujian)===examSel.value)&&(!kelasSel||kelasSel.value==="all"||x.kelas===kelasSel.value));
      oldRenderHasil(page);
      window.adminState.hasil=original;
    }
  };
  document.addEventListener("DOMContentLoaded",()=>{injectJadwalToolbar();injectAuditCard();injectHasilFilters();});
}();
